// // This module implements a 3-bit synchronous binary down counter. The counter decrements its value by 1 on each positive edge of the clock signal. The counter resets to 3'b111 when the reset signal (rst) is active.
module binary_up_counter_3 
(
  input rst,
  input clk,

  output reg [2:0] count
);

  always @(posedge clk or posedge rst) begin
    if (rst) 
	begin
      count <= 3'b000;
    end 
	else 
	begin
      count <= count + 1;
    end
  end

endmodule
